//! Synthetic FLUX-VAE knot builder — shared by the VAE forward-proof PoC bin
//! and the local image-serving endpoint.
//!
//! Fabricates a small (~200 MB) but STRUCTURALLY COMPLETE synthetic FLUX
//! AutoencoderKL decoder knot at REAL FLUX dims (conv_in 16→512, mid
//! resnet/self-attn/resnet, 4 up-blocks = 12 resnets + 3 ×2 upsamplers,
//! GroupNorm/SiLU, conv_out→3). Only the weight VALUES are synthetic
//! (fan-in scaled, finite). The KNOT container, tensor shapes, Q8_0 attention
//! linears, and the loader/kernel code path are the production ones — so a
//! successful `FluxVae::load` + `decode` over this knot forward-PROVES the real
//! decoder kernel (it is NOT a prompt-faithful generator: no DiT, no real
//! weights).

#![cfg(not(target_arch = "wasm32"))]

use crate::model_flux_mmdit::FLUX_LATENT_CHANNELS;

// ───────────────────────── deterministic RNG ─────────────────────────

/// FNV-1a 64-bit name hash → per-tensor seed (reproducible across runs).
pub fn name_seed(name: &str) -> u64 {
    let mut h = 0xCBF2_9CE4_8422_2325u64;
    for b in name.bytes() {
        h ^= b as u64;
        h = h.wrapping_mul(0x0000_0100_0000_01B3);
    }
    h | 1
}

/// splitmix64 → uniform f32 in (-1, 1).
pub fn rand_unit(state: &mut u64) -> f32 {
    *state = state.wrapping_add(0x9E37_79B9_7F4A_7C15);
    let mut z = *state;
    z = (z ^ (z >> 30)).wrapping_mul(0xBF58_476D_1CE4_E5B9);
    z = (z ^ (z >> 27)).wrapping_mul(0x94D0_49BB_1331_11EB);
    z ^= z >> 31;
    let u = (z >> 40) as f32 / (1u32 << 24) as f32;
    2.0 * u - 1.0
}

/// Box-Muller standard normal from the splitmix64 stream.
pub fn gaussian(state: &mut u64) -> f32 {
    let u1 = ((rand_unit(state) + 1.0) * 0.5).clamp(1e-7, 1.0 - 1e-7);
    let u2 = (rand_unit(state) + 1.0) * 0.5;
    (-2.0 * u1.ln()).sqrt() * (std::f32::consts::TAU * u2).cos()
}

/// f32 → IEEE-754 half (round-to-nearest); used for Q8_0 block scales (small
/// positive values, so the normal-range path suffices).
pub fn f32_to_f16(value: f32) -> u16 {
    let bits = value.to_bits();
    let sign = ((bits >> 16) & 0x8000) as u16;
    let mut exp = ((bits >> 23) & 0xff) as i32 - 127 + 15;
    let mant = bits & 0x007f_ffff;
    if exp <= 0 {
        return sign;
    }
    if exp >= 0x1f {
        return sign | 0x7c00;
    }
    let mut m10 = (mant >> 13) as u16;
    if (mant & 0x1000) != 0 {
        m10 += 1;
        if m10 == 0x400 {
            m10 = 0;
            exp += 1;
            if exp >= 0x1f {
                return sign | 0x7c00;
            }
        }
    }
    sign | ((exp as u16) << 10) | m10
}

// ───────────────────────── synthetic weights ─────────────────────────

fn fp32_weight(name: &str, n: usize, fan_in: usize) -> Vec<u8> {
    let mut st = name_seed(name);
    let scale = if fan_in > 0 {
        (3.0f32 / fan_in as f32).sqrt()
    } else {
        0.0
    };
    let mut buf = Vec::with_capacity(n * 4);
    for _ in 0..n {
        buf.extend_from_slice(&(rand_unit(&mut st) * scale).to_le_bytes());
    }
    buf
}

fn fp32_const(n: usize, value: f32) -> Vec<u8> {
    let le = value.to_le_bytes();
    let mut buf = Vec::with_capacity(n * 4);
    for _ in 0..n {
        buf.extend_from_slice(&le);
    }
    buf
}

/// Q8_0 weight in the per-row layout `mat_vec_q8_0` expects (blocks of 32:
/// f16 scale + 32 i8). Requires `cols % 32 == 0` (true for the 512-wide VAE
/// attention linears).
fn q8_0_weight(name: &str, rows: usize, cols: usize) -> Vec<u8> {
    assert_eq!(cols % 32, 0, "q8 cols must be multiple of 32");
    let mut st = name_seed(name);
    let scale = (3.0f32 / cols as f32).sqrt();
    let mut buf = Vec::with_capacity(rows * (cols / 32) * 34);
    for _ in 0..rows {
        let row: Vec<f32> = (0..cols).map(|_| rand_unit(&mut st) * scale).collect();
        for block in row.chunks(32) {
            let amax = block.iter().fold(0.0f32, |a, &b| a.max(b.abs()));
            let blk_scale = if amax > 0.0 { amax / 127.0 } else { 1.0 };
            buf.extend_from_slice(&f32_to_f16(blk_scale).to_le_bytes());
            for &v in block {
                let q = (v / blk_scale).round().clamp(-127.0, 127.0) as i32 as i8;
                buf.push(q as u8);
            }
        }
    }
    buf
}

// ───────────────────────── knot builder ─────────────────────────

struct Tensor {
    name: String,
    ttype: &'static str,
    shape: Vec<usize>,
    bytes: Vec<u8>,
}

#[derive(Default)]
struct Builder {
    tensors: Vec<Tensor>,
}

impl Builder {
    fn conv(&mut self, name: &str, out_c: usize, in_c: usize, k: usize) {
        let fan_in = in_c * k * k;
        self.tensors.push(Tensor {
            name: format!("{name}_weight"),
            ttype: "fp32",
            shape: vec![out_c, in_c, k, k],
            bytes: fp32_weight(&format!("{name}_weight"), out_c * in_c * k * k, fan_in),
        });
        self.tensors.push(Tensor {
            name: format!("{name}_bias"),
            ttype: "fp32",
            shape: vec![out_c],
            bytes: fp32_const(out_c, 0.0),
        });
    }

    fn norm(&mut self, name: &str, c: usize) {
        self.tensors.push(Tensor {
            name: format!("{name}_weight"),
            ttype: "fp32",
            shape: vec![c],
            bytes: fp32_const(c, 1.0),
        });
        self.tensors.push(Tensor {
            name: format!("{name}_bias"),
            ttype: "fp32",
            shape: vec![c],
            bytes: fp32_const(c, 0.0),
        });
    }

    fn q8_linear(&mut self, name: &str, rows: usize, cols: usize) {
        self.tensors.push(Tensor {
            name: format!("{name}_weight"),
            ttype: "Q8_0",
            shape: vec![rows, cols],
            bytes: q8_0_weight(&format!("{name}_weight"), rows, cols),
        });
        self.tensors.push(Tensor {
            name: format!("{name}_bias"),
            ttype: "fp32",
            shape: vec![rows],
            bytes: fp32_const(rows, 0.0),
        });
    }

    /// diffusers ResnetBlock2D: norm1(in) conv1(in→out) norm2(out) conv2(out→out)
    /// + optional 1×1 conv_shortcut(in→out) when channels change.
    fn resnet(&mut self, prefix: &str, in_c: usize, out_c: usize) {
        self.norm(&format!("{prefix}_norm1"), in_c);
        self.conv(&format!("{prefix}_conv1"), out_c, in_c, 3);
        self.norm(&format!("{prefix}_norm2"), out_c);
        self.conv(&format!("{prefix}_conv2"), out_c, out_c, 3);
        if in_c != out_c {
            self.conv(&format!("{prefix}_conv_shortcut"), out_c, in_c, 1);
        }
    }

    fn flux_vae_decoder(&mut self) {
        let pre = "flux_vae_decoder";
        self.conv(&format!("{pre}_conv_in"), 512, FLUX_LATENT_CHANNELS, 3);
        self.resnet(&format!("{pre}_mid_block_resnets_0"), 512, 512);
        let attn = format!("{pre}_mid_block_attentions_0");
        self.norm(&format!("{attn}_group_norm"), 512);
        self.q8_linear(&format!("{attn}_to_q"), 512, 512);
        self.q8_linear(&format!("{attn}_to_k"), 512, 512);
        self.q8_linear(&format!("{attn}_to_v"), 512, 512);
        self.q8_linear(&format!("{attn}_to_out_0"), 512, 512);
        self.resnet(&format!("{pre}_mid_block_resnets_1"), 512, 512);
        // diffusers reversed block_out_channels = [512, 512, 256, 128]
        let out_channels = [512usize, 512, 256, 128];
        let mut prev = 512usize;
        for (b, &out_c) in out_channels.iter().enumerate() {
            for r in 0..3usize {
                let in_c = if r == 0 { prev } else { out_c };
                self.resnet(&format!("{pre}_up_blocks_{b}_resnets_{r}"), in_c, out_c);
            }
            prev = out_c;
            if b != out_channels.len() - 1 {
                self.conv(&format!("{pre}_up_blocks_{b}_upsamplers_0_conv"), out_c, out_c, 3);
            }
        }
        self.norm(&format!("{pre}_conv_norm_out"), 128);
        self.conv(&format!("{pre}_conv_out"), 3, 128, 3);
    }

    fn serialize(&self) -> Vec<u8> {
        let mut payload = Vec::new();
        let mut meta_tensors = serde_json::Map::new();
        for t in &self.tensors {
            let offset = payload.len() as u64;
            payload.extend_from_slice(&t.bytes);
            meta_tensors.insert(
                t.name.clone(),
                serde_json::json!({
                    "offset": offset,
                    "length": t.bytes.len() as u64,
                    "type": t.ttype,
                    "shape": t.shape,
                }),
            );
        }
        let metadata = serde_json::json!({
            "name": "synthetic-flux-vae",
            "codec": "fp32",
            "tensors": meta_tensors,
        });
        let meta_bytes = serde_json::to_vec(&metadata).expect("serialize metadata");
        let mut out = Vec::with_capacity(meta_bytes.len() + payload.len() + 32);
        out.extend_from_slice(b"KNOT");
        out.extend_from_slice(&1u16.to_le_bytes());
        out.extend_from_slice(&(meta_bytes.len() as u32).to_le_bytes());
        out.extend_from_slice(&meta_bytes);
        while out.len() % 4 != 0 {
            out.push(0);
        }
        out.push(0x20); // codec marker byte
        out.extend_from_slice(&payload);
        out
    }
}

/// Serialize a complete synthetic FLUX-VAE-decoder knot (KNOT v1 container).
/// Returns `(bytes, tensor_count)`.
pub fn synthetic_flux_vae_knot_bytes() -> (Vec<u8>, usize) {
    let mut b = Builder::default();
    b.flux_vae_decoder();
    let n = b.tensors.len();
    (b.serialize(), n)
}

/// Write the synthetic knot to `path`; returns the tensor count.
pub fn write_synthetic_flux_vae_knot(path: &std::path::Path) -> std::io::Result<usize> {
    let (bytes, n) = synthetic_flux_vae_knot_bytes();
    std::fs::write(path, &bytes)?;
    Ok(n)
}
